function closestNodes(n, edges, query) {
    const answer = [];
    const tree = Array.from({ length: n }, () => []);

    for (const edge of edges) {
        tree[edge[0]].push(edge[1]);
        tree[edge[1]].push(edge[0]);
    }

    function bfs(start, end) {
        const queue = [start];
        const visited = new Set([start]);

        while (queue.length > 0) {
            const current = queue.shift();

            if (current === end) {
                return current;
            }

            for (const neighbor of tree[current]) {
                if (!visited.has(neighbor)) {
                    queue.push(neighbor);
                    visited.add(neighbor);
                }
            }
        }
    }

    for (const q of query) {
        const lca = bfs(q[0], q[1]);
        const node1 = bfs(lca, q[0]);
        const node2 = bfs(lca, q[1]);
        answer.push(node1 === q[2] ? q[0] : q[1]);
    }

    return answer;
}
```

